const body = $input.first().json.body || $input.first().json;

const respondentRaw = body.respondent || 'unknown:unknown';
const [respondentType, respondentSlug] = respondentRaw.includes(':')
  ? respondentRaw.split(':', 2)
  : ['unknown', respondentRaw];

return [{
  json: {
    instance_name:    body.instanceName,
    message_id:       body.messageId,
    remote_jid:       body.remote_jid || body.from,
    conteudo_raw:     body.body || null,
    tipo:             body.message_type || 'text',
    audio_url:        body.audio_url || null,
    direction:        body.type || 'unknown',
    respondent_type:  respondentType,
    respondent_slug:  respondentSlug,
    respondent_name:  body.attendant_name || null,
    area:             body.sector || 'comercial',
    external_session_id: body.session_id || null,
    timestamp:        body.timestamp || new Date().toISOString(),
    metadados:        body
  }
}];

const payload = $('Normalizar Payload EsteticaIA').first().json;
const lookup = $input.first().json;

return [{
  json: {
    ...payload,
    instancia_id: lookup.instancia_id || null,
    numero_id:    lookup.numero_id || null,
    projeto_id:   lookup.projeto_id || null,
    numero_tipo:  lookup.numero_tipo || 'multi'
  }
}];

const dados = $('Enriquecer com Projeto').first().json;
let agente_humano_id = null;

if (dados.respondent_type !== 'ai') {
  try {
    const r = $('Lookup Agente Respondente').first().json;
    agente_humano_id = r.agente_humano_id || null;
  } catch(e) { agente_humano_id = null; }
}

return [{ json: { ...dados, agente_humano_id } }];
